const margin = (r, w) => Math.round(((r - w) / r) * 100);

const PriceTable = ({ rows }) => (
  <div
    style={{
      overflowX: "auto",
      borderRadius: 10,
      border: `1px solid ${GREEN}22`,
    }}
  >
    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
      <thead>
        <tr style={{ background: GREEN }}>
          {["Dimensions", "Wholesale", "Retail", "Margin"].map((h) => (
            <th
              key={h}
              style={{
                padding: "8px 12px",
                textAlign: h === "Dimensions" ? "left" : "right",
                color: "#fff",
                fontWeight: 600,
                letterSpacing: "0.02em",
                whiteSpace: "nowrap",
                fontSize: 12,
              }}
            >
              {h}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.map((row, i) => {
          const m = margin(row.retail, row.wholesale);
          return (
            <tr
              key={i}
              style={{
                background: i % 2 === 0 ? "#fff" : "#f7faf6",
                borderTop: `1px solid ${GREEN}18`,
              }}
            >
              <td
                style={{ padding: "7px 12px", color: "#222", fontWeight: 500 }}
              >
                {row.dimensions}
              </td>
              <td
                style={{
                  padding: "7px 12px",
                  textAlign: "right",
                  color: GREEN,
                  fontWeight: 700,
                }}
              >
                ${row.wholesale.toFixed(2)}
              </td>
              <td
                style={{
                  padding: "7px 12px",
                  textAlign: "right",
                  color: "#666",
                }}
              >
                ${row.retail}
              </td>
              <td style={{ padding: "7px 12px", textAlign: "right" }}>
                <span
                  style={{
                    background:
                      m >= 60 ? "#e8f5e3" : m >= 50 ? "#fdf3e3" : "#f5f5f5",
                    color: m >= 60 ? GREEN : m >= 50 ? AMBER : "#666",
                    fontWeight: 700,
                    fontSize: 12,
                    padding: "2px 7px",
                    borderRadius: 20,
                  }}
                >
                  {m}%
                </span>
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  </div>
);

